try (Socket socket = new Socket("ejemplo.com", 80)) {
    PrintWriter out = new PrintWriter(socket.getOutputStream(), true);
    out.println("GET / HTTP/1.1");
    out.println("Host: ejemplo.com");
    out.println("Connection: close");
    out.println();
    BufferedReader in = new BufferedReader(new InputStreamReader(socket.getInputStream()));
    String linea;
    while ((linea = in.readLine()) != null) System.out.println(linea);
}

try (ServerSocket server = new ServerSocket(8080)) {
    System.out.println("Esperando cliente...");
    try (Socket cliente = server.accept()) {
        BufferedReader in = new BufferedReader(new InputStreamReader(cliente.getInputStream()));
        PrintWriter out = new PrintWriter(cliente.getOutputStream(), true);
        out.println("Hola cliente");
        System.out.println(in.readLine());
    }
}

URL url = new URL("https://api.github.com/users/octocat");
HttpURLConnection conn = (HttpURLConnection) url.openConnection();
conn.setRequestMethod("GET");
try (BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()))) {
    br.lines().forEach(System.out::println);
}

// Enviar
byte[] buffer = "Hola".getBytes();
InetAddress addr = InetAddress.getByName("localhost");
DatagramPacket packet = new DatagramPacket(buffer, buffer.length, addr, 5000);
DatagramSocket socket = new DatagramSocket();
socket.send(packet);

// Recibir
byte[] buffer = new byte[1024];
DatagramPacket packet = new DatagramPacket(buffer, buffer.length);
DatagramSocket socket = new DatagramSocket(5000);
socket.receive(packet);
String msg = new String(packet.getData(), 0, packet.getLength());
